mapper.select:
SELECT ice.id AS id, frame.name AS frame, customer.name AS customer, ice.time AS time, ice.number AS number, ice.total AS total, ice.actual AS actual, ice.money AS money, account.name AS account, people.name AS people, ice.data AS data, ice.examine AS examine, ice.nucleus AS nucleus, user.name AS user, ice_bill.id AS billId, ice_bill.money AS billMoney FROM ice left join ice_bill on ice.id = ice_bill.pid left join ice_info on ice.id = ice_info.pid left join customer on ice.customer = customer.id left join frame on ice.frame = frame.id left join account on ice.account = account.id left join people on ice.people = people.id left join user on ice.user = user.id
AND ice.id IN
#{id}
